create table roma_main.vermarktungscluster (
    vc_lfd_nr                  number(38, 0)
        generated by default on null as identity minvalue 1 maxvalue 9999999999999999999999999999 increment by 1 start with 61 cache 20
        noorder nocycle nokeep noscale
    not null enable,
    bezeichnung                varchar2(4000 byte),
    dnsttp_lfd_nr              number(38, 0) not null enable,
    url                        varchar2(4000 byte),
    status                     varchar2(4000 byte),
    ausbau_plan_termin         date,
    aktiv                      number,
    mindestbandbreite          number(6, 0) not null enable,
    zielbandbreite_geplant     number(6, 0) default on null 1000 not null enable,
    kosten_hausanschluss       number not null enable,
    kundenauftrag_erforderlich number(1, 0) not null enable,
    netwissen_seite            varchar2(4000 byte) not null enable,
    inserted                   date,
    updated                    date,
    inserted_by                varchar2(4000 byte),
    updated_by                 varchar2(4000 byte),
    url_gk                     varchar2(255 byte) default 'https://www.netcologne.de/geschaeftskunden/internet/glasfaser-tarife-landingpage/'
    not null enable,
    wholebuy                   varchar2(30 byte),
    mandant                    varchar2(2 byte),
    loeschgrund                number,
    anlage_typ                 varchar2(100 byte) default 'MANUELL'
);

create unique index roma_main.vc_pk on
    roma_main.vermarktungscluster (
        vc_lfd_nr
    );

alter table roma_main.vermarktungscluster
    add constraint vc_pk
        primary key ( vc_lfd_nr )
            using index roma_main.vc_pk enable;

alter table roma_main.vermarktungscluster flashback archive mongo


